// Generate SQL
let sql = `-- Fix any NULL values in numeric columns
UPDATE problems SET total_submissions = 0 WHERE total_submissions IS NULL;
UPDATE problems SET accepted_submissions = 0 WHERE accepted_submissions IS NULL;
UPDATE problems SET time_limit_ms = 2000 WHERE time_limit_ms IS NULL;
UPDATE problems SET memory_limit_mb = 256 WHERE memory_limit_mb IS NULL;

-- Seed 250 HARD problems
`;

const startId = 10001; // Start from high ID to avoid conflicts
let tcId = 100001;

for (let i = 0; i < problems.length; i++) {
  const p = problems[i];
  const pid = startId + i;
  const escTitle = p.title.replace(/'/g, "''");
  const escDesc = p.desc.replace(/'/g, "''");
  const escInp = p.inp.replace(/'/g, "''");
  const escOut = p.out.replace(/'/g, "''");
  const escCon = p.constraints.replace(/'/g, "''");
  const escSI = p.tc[0][0].replace(/'/g, "''");
  const escSO = p.tc[0][1].replace(/'/g, "''"); 
  const escCat = p.cat.replace(/'/g, "''");

  sql += `\nINSERT INTO problems (id, title, description, difficulty, input_format, output_format, constraints, sample_input, sample_output, category, total_submissions, accepted_submissions, time_limit_ms, memory_limit_mb, created_at)
VALUES (${pid}, '${escTitle}', '${escDesc}', 'HARD', '${escInp}', '${escOut}', '${escCon}', '${escSI}', '${escSO}', '${escCat}', 0, 0, 3000, 512, NOW())
ON CONFLICT (id) DO NOTHING;\n`;

  // Test cases
  for (let j = 0; j < p.tc.length; j++) {
    const tc = p.tc[j];
    const escInput = tc[0].replace(/'/g, "''");
    const escExpected = tc[1].replace(/'/g, "''");
    sql += `INSERT INTO test_cases (id, problem_id, input, expected_output, is_sample, order_index) VALUES (${tcId++}, ${pid}, '${escInput}', '${escExpected}', ${j === 0}, ${j}) ON CONFLICT (id) DO NOTHING;\n`;
  }
}

sql += `\n-- Reset sequences to avoid ID conflicts
SELECT setval('problems_id_seq', (SELECT COALESCE(MAX(id), 0) FROM problems));
SELECT setval('test_cases_id_seq', (SELECT COALESCE(MAX(id), 0) FROM test_cases));
`;

console.log(`Generated ${problems.length} problems`);
fs.writeFileSync('backend/src/main/resources/data.sql', sql, 'utf8');
console.log('Written to data.sql');
